#if UNITY_EDITOR
using UnityEditor;
using UnityEngine;

/// <summary>
/// Editor customizado do EnemyAttackController (Enemy Creator — Etapa 2.1).
///
/// Usa PolymorphicListDrawer (mesmo utilitário de EnemyControllerEditor /
/// NpcControllerEditor) para listar/adicionar subclasses concretas de
/// EnemyAttack na lista <see cref="EnemyAttackController.attacks"/> — inclui
/// automaticamente todas as classes "Attack_*" definidas em Enemy/Attacks/.
/// </summary>
[CustomEditor(typeof(EnemyAttackController))]
public class EnemyAttackControllerEditor : Editor
{
    private SerializedProperty _attacksProp;

    private void OnEnable()
    {
        _attacksProp = serializedObject.FindProperty("attacks");
    }

    public override void OnInspectorGUI()
    {
        serializedObject.Update();

        DrawPropertiesExcluding(serializedObject, "m_Script", "attacks");

        EditorGUILayout.Space();
        PolymorphicListDrawer.Draw(serializedObject, _attacksProp, "Ataques (Etapa 2.1)", typeof(EnemyAttack), "Adicionar Ataque");

        serializedObject.ApplyModifiedProperties();
    }
}
#endif
